noncompliant:
// C++14 attribute
[[deprecated("Use newFunction instead.")]]
void oldFunction();

// GNU attribute
__attribute__((deprecated("Use newFunction instead.")))
void oldFunction();

// Microsoft attribute
__declspec(deprecated("Use newFunction instead."))
void oldFunction();

void newFunction();

void example() {
  oldFunction(); // Noncompliant
}

compliant:
void newFunction(); // Use the recommended replacement

void example() {
  newFunction(); // Compliant: using non-deprecated function
}

// Remove deprecated function calls entirely
void modernImplementation() {
  // Use current best practices
  printf("Modern approach");
}
